public class PowerOfThree {

    public static void main(String[] args) {
        System.out.println(isPowerOfThree(27)); // true
        System.out.println(isPowerOfThree(0));  // false
        System.out.println(isPowerOfThree(-1)); // false

        System.out.println(isPowerOfThreeNoLoop(27)); // true
        System.out.println(isPowerOfThreeNoLoop(0));  // false
        System.out.println(isPowerOfThreeNoLoop(-1)); // false
    }

    public static boolean isPowerOfThree(int n) {
        if (n <= 0) {
            return false;
        }

        while (n % 3 == 0) {
            n /= 3;
        }

        return n == 1;
    }

    public static boolean isPowerOfThreeNoLoop(int n) {
        if (n <= 0) {
            return false;
        }

        // The largest power of 3 that fits in an int is 3^19 = 1162261467.
        // If n is a power of 3, it must be a factor of 1162261467.
        return 1162261467 % n == 0;
    }
}
